def get_klines(symbol, limit=200):
    code, d = _req('GET', '/fapi/v1/klines', {'symbol':symbol,'interval':INTERVAL,'limit':limit})
    if code != 200: return None
    out = []
    for c in d:
        out.append({'ts':int(c[0]),'open':float(c[1]),'high':float(c[2]),
                    'low':float(c[3]),'close':float(c[4]),'volume':float(c[5])})
    return out

_PRECISION={}
def get_precision(symbol):
    """Return (qty_step, qty_decimals) from exchangeInfo LOT_SIZE filter."""
    if symbol in _PRECISION: return _PRECISION[symbol]
    code,d=_req('GET','/fapi/v1/exchangeInfo',{'symbol':symbol})
    step=0.001; dec=3
    if code==200:
        si=next((s for s in d['symbols'] if s['symbol']==symbol),None)
        if si:
            for f in si['filters']:
                if f['filterType']=='LOT_SIZE':
                    step=float(f['stepSize']); break
            # decimals from step
            dec=0
            x=step
            while x<1: x*=10; dec+=1
    _PRECISION[symbol]=(step,dec)
    return _PRECISION[symbol]

def round_qty(symbol, qty):
    step,dec=get_precision(symbol)
    q=round(qty/step)*step
    return round(q, dec)

_PRICE_DEC={}
def get_price_dec(symbol):
    if symbol in _PRICE_DEC: return _PRICE_DEC[symbol]
    code,d=_req('GET','/fapi/v1/exchangeInfo',{'symbol':symbol})
    dec=2
    if code==200:
        si=next((s for s in d['symbols'] if s['symbol']==symbol),None)
        if si:
            for f in si['filters']:
                if f['filterType']=='PRICE_FILTER':
                    tick=float(f['tickSize']); break
            dec=0; x=tick
            while x<1: x*=10; dec+=1
    _PRICE_DEC[symbol]=dec
    return dec

def round_price(symbol, p):
    return round(p, get_price_dec(symbol))

def setup_leverage(symbol):
    _req('POST', '/fapi/v1/leverage', {'symbol':symbol,'leverage':LEVERAGE}, signed=True)

def get_price(symbol):
    code, d = _req('GET', '/fapi/v1/ticker/price', {'symbol':symbol})
    return float(d['price']) if code==200 else None

def get_balance():
    code, d = _req('GET', '/fapi/v2/account', signed=True)
    if code != 200: return None
    return float(d.get('availableBalance', 0))

def place_market(symbol, side, qty):
    params = {'symbol':symbol,'side':side,'type':'MARKET','quantity':f'{qty:.6f}'}
    return _req('POST', '/fapi/v1/order', params, signed=True)

def place_algo_sl_tp(symbol, side, qty, sl_price, tp_price):
    """Place SL & TP via Algo Order API (mandatory on testnet since Dec 2025)."""
    ids = []
    sl_side = 'SELL' if side=='BUY' else 'BUY'
    qstr = f'{qty:.6f}'
    sl_r = round_price(symbol, sl_price)
    tp_r = round_price(symbol, tp_price)
    # SL (STOP_MARKET)
    p = {'symbol':symbol,'algoType':'CONDITIONAL','type':'STOP_MARKET',
         'side':sl_side,'quantity':qstr,
         'triggerPrice':f'{sl_r}','workingType':'MARK_PRICE'}
    code, d = _req('POST', '/fapi/v1/algoOrder', p, signed=True)
    if code == 200 and 'algoId' in d:
        ids.append(d['algoId'])
    else:
        print(f"  ⚠️ SL algo failed {symbol}: {code} {d}")
    # TP (TAKE_PROFIT_MARKET)
    p2 = {'symbol':symbol,'algoType':'CONDITIONAL','type':'TAKE_PROFIT_MARKET',
          'side':sl_side,'quantity':qstr,
          'triggerPrice':f'{tp_r}','workingType':'MARK_PRICE'}
    code2, d2 = _req('POST', '/fapi/v1/algoOrder', p2, signed=True)
    if code2 == 200 and 'algoId' in d2:
        ids.append(d2['algoId'])
    else:
        print(f"  ⚠️ TP algo failed {symbol}: {code2} {d2}")
    return ids

def cancel_algo(symbol, algo_id):
    return _req('DELETE', '/fapi/v1/algoOrder', {'symbol':symbol,'algoId':str(algo_id)}, signed=True)

def has_position(symbol):
    code, d = _req('GET', '/fapi/v2/positionRisk', signed=True)
    if code != 200: return False
    for p in d:
        if p['symbol']==symbol and abs(float(p['positionAmt']))>1e-6:
            return True
    return False

# ===== STRATEGY (BoS_PA) =====
def detect_swings(candles, n=SWING):
    hi=[c['high'] for c in candles]; lo=[c['low'] for c in candles]
    sh=[]; sl=[]
    for i in range(n, len(candles)-n):
        win_h=hi[i-n:i+n+1]; win_l=lo[i-n:i+n+1]
        if hi[i]==max(win_h): sh.append(i)
        if lo[i]==min(win_l): sl.append(i)
    return sh, sl

def bos_signal(candles, sh, sl):
    n=len(candles)
    if n < SWING*2: return 0
    i=n-2  # penultimate candle (last is forming)
    c=candles[i]['close']
    jh=bisect.bisect_left(sh,i); jl=bisect.bisect_left(sl,i)
    if jh>0 and c>candles[sh[jh-1]]['high']: return 1
    if jl>0 and c<candles[sl[jl-1]]['low']: return -1
    return 0

# ===== STATE =====
def load_state():
    if os.path.exists(STATE_FILE):
        try: return json.load(open(STATE_FILE))
        except: pass
    return {'positions':{}, 'algo_ids':{}}

def save_state(st):
    json.dump(st, open(STATE_FILE,'w'), indent=2)

# ===== MAIN LOOP =====
_running=True
def _sig(s,f):
    global _running; _running=False

def run_once():
    """Single pass: scan all symbols, open trades if signal. Returns #opened."""
    opened=0
    st=load_state()
    for sym in SYMBOLS:
        if sym in st['positions']:
            continue
        kl=get_klines(sym, 200)
        if not kl: continue
        sh,sl=detect_swings(kl)
        sig=bos_signal(kl, sh, sl)
        if sig==0: continue
        price=get_price(sym)
        if not price: continue
        sl_dist=max(price*0.002, 1e-6)
        sl_price=price-sl_dist if sig==1 else price+sl_dist
        tp_price=price+sl_dist*RR if sig==1 else price-sl_dist*RR
        side='BUY' if sig==1 else 'SELL'
        qty=round_qty(sym, RISK_USD/sl_dist)
        if qty<=0: continue
        code,d=place_market(sym, side, qty)
        if code==200 and 'orderId' in d:
            aids=place_algo_sl_tp(sym, side, qty, sl_price, tp_price)
            st['positions'][sym]={'side':side,'entry':price,'sl':sl_price,'tp':tp_price,'qty':qty,'algo':aids,'t':int(time.time())}
            st['algo_ids'][sym]=aids
            save_state(st)
            print(f"  ✅ {sym} {side} @ {price:.4f} | SL={sl_price:.4f} TP={tp_price:.4f} qty={qty:.2f} algo={aids}")
            opened+=1
        else:
            print(f"  ❌ {sym} order failed: {code} {str(d)[:120]}")
    return opened

def main():
    global _running

